    "/search": {
        parameters: {
            query?: never;
            header?: never;
            path?: never;
            cookie?: never;
        };
        /**
         * Search
         * @description Hybrid search across all documents. Returns results grouped by document.
         *
         *     When ``document_id`` is supplied, retrieval is scoped to that single
         *     document. Eval pipelines need this to measure per-document
         *     retrieval quality without having the target document drowned out by
         *     the rest of the corpus in global ranking.
         *
         *     When ``hyde`` is true, the retriever calls the local LLM to generate a
         *     hypothetical answer and uses ``"<q> <answer>"`` for retrieval. Slower
         *     by one LLM call (~1s) but bridges question/answer phrasing divergence.
         *
         *     When ``graph_expand`` is true (default), entities detected in the query
         *     are resolved to canonical labels via Kuzu's alias graph and appended to
         *     the query. Deterministic and local-first per I-16; pairs with
         *     index-time entity injection.
         *
         *     When ``rerank`` is true, the top-N RRF candidates (``rerank_depth``,
         *     default from ``RERANK_DEPTH`` settings) are re-scored by a cross-encoder
         *     and the top-``limit`` returned; candidates scoring below
         *     ``rerank_threshold`` (default ``RERANK_SCORE_THRESHOLD``) are cut. Adds
         *     ~100-300ms per query at depth 50 (CPU, linear in depth) but recovers
         *     answer chunks whose vocabulary diverges from the question's surface
         *     form -- the remaining failure mode after HyDE. Local-first per I-16.
         *     Fails soft on any reranker error.
         */
        get: operations["search_search_get"];
        put?: never;
        post?: never;
        delete?: never;
        options?: never;
        head?: never;
        patch?: never;
        trace?: never;
    };
